import React, { useEffect, useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

export default function BusCharts({ buses }) {
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    const timestamp = new Date().toLocaleTimeString();

    const runningCount = buses.filter((b) => b.status === "Running").length;
    const ghostCount = buses.filter((b) => b.status === "Ghost").length;
    const anomalyCount = buses.filter((b) => b.status === "Anomaly").length;

    // Add new data point
    setChartData((prev) => [
      ...prev.slice(-19), // keep only last 20 data points for clarity
      {
        time: timestamp,
        Running: runningCount,
        Ghost: ghostCount,
        Anomaly: anomalyCount,
      },
    ]);
  }, [buses]);

  return (
    <ResponsiveContainer width="100%" height="100%">
      <LineChart
        data={chartData}
        margin={{ top: 10, right: 20, left: 0, bottom: 0 }}
      >
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="time" />
        <YAxis allowDecimals={false} />
        <Tooltip />
        <Legend verticalAlign="top" height={36} />
        <Line
          type="monotone"
          dataKey="Running"
          stroke="green"
          strokeWidth={2}
          dot={{ r: 3 }}
        />
        <Line
          type="monotone"
          dataKey="Ghost"
          stroke="red"
          strokeWidth={2}
          dot={{ r: 3 }}
        />
        <Line
          type="monotone"
          dataKey="Anomaly"
          stroke="orange"
          strokeWidth={2}
          dot={{ r: 3 }}
        />
      </LineChart>
    </ResponsiveContainer>
  );
}
